                 </div>
               </div>
               <div className="col-md-3">
                 <div className="card bg-primary text-white">
                    <div className="card-body py-3">
                        <small className="opacity-75">Rata-rata Kelas</small>
                        <h4 className="fw-bold mb-0">{stats.avg.toFixed(1)}</h4>
