                            onChange={e => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div className="col-md-5">
                        <select
                            className="form-select"
                            value={filterClass}
                            onChange={e => setFilterClass(e.target.value)}
                        >
                            <option value="">Semua Kelas</option>
                            {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                </div>
             </div>

             <div className="table-responsive">
                <table id="student-table" className="table table-hover table-striped mb-0 align-middle">
                    <thead className="table-light">
                        <tr>
                        <th className="ps-3">NISN</th>
                        <th>Nama</th>
                        <th>L/P</th>
                        <th>Kelas</th>
                        <th className="text-end pe-3 no-print">Aksi</th>
                        </tr>
                    </thead>
                    <tbody>
                        {currentData.length > 0 ? currentData.map(s => (
                        <tr key={s.id}>
                            <td className="ps-3 small text-muted">{s.nisn}</td>
                            <td className="fw-bold">{s.name}</td>
                            <td>{s.gender}</td>
                            <td>
                                <span className="badge bg-light text-dark border">
                                    {classes.find(c => c.id === s.classId)?.name || '-'}
                                </span>
                            </td>
                            <td className="text-end pe-3 no-print">
                                <button onClick={() => handleEdit(s)} className="btn btn-sm btn-link text-decoration-none">Edit</button>
                                <button onClick={() => handleDelete(s.id, s.name)} className="btn btn-sm btn-link text-danger text-decoration-none">Hapus</button>
                            </td>
                        </tr>
                        )) : (
                            <tr><td colSpan={5} className="text-center py-4 text-muted">Tidak ada data siswa ditemukan</td></tr>
                        )}
                    </tbody>
                </table>
             </div>

             {/* Pagination */}
             {totalPages > 1 && (
                 <div className="card-footer bg-white d-flex justify-content-end no-print">
                    <nav>
                        <ul className="pagination pagination-sm mb-0">
                            <li className={`page-item ${currentPage === 1 ? 'disabled' : ''}`}>
                                <button className="page-link" onClick={() => setCurrentPage(c => Math.max(c - 1, 1))}>Previous</button>
                            </li>
                            {Array.from({length: totalPages}, (_, i) => (
                                <li key={i} className={`page-item ${currentPage === i + 1 ? 'active' : ''}`}>
                                    <button className="page-link" onClick={() => setCurrentPage(i + 1)}>{i + 1}</button>
                                </li>
                            ))}
                            <li className={`page-item ${currentPage === totalPages ? 'disabled' : ''}`}>
                                <button className="page-link" onClick={() => setCurrentPage(c => Math.min(c + 1, totalPages))}>Next</button>
                            </li>
                        </ul>
                    </nav>
                 </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Student, GradeData, Classroom } from '../types';
import { getClasses, getStudentsByClass, getGradeByStudent, saveGrade, getUserProfile } from '../services/storageService';
import { KKM, WEIGHTS, SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';

export const GradingSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [grades, setGrades] = useState<Record<string, GradeData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      // Data students already sorted A-Z from service
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const gradeMap: Record<string, GradeData> = {};
      clsStudents.forEach(s => {
        gradeMap[s.id] = getGradeByStudent(s.id);
      });
      setGrades(gradeMap);
    }
  }, [selectedClass]);

  const handleGradeChange = (studentId: string, field: 'formatif' | 'sumatif', index: number, value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId] };
    if (field === 'formatif') {
      const newF = [...currentGrade.formatif];
      newF[index] = numVal;
      currentGrade.formatif = newF;
    } else {
      const newS = [...currentGrade.sumatif];
      newS[index] = numVal;
      currentGrade.sumatif = newS;
    }
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  const handleSasChange = (studentId: string, field: 'sasNonTes' | 'sasTes', value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId], [field]: numVal };
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  const getLetterGrade = (score: number) => {
      if (score >= 90) return { letter: 'A', color: 'bg-success' };
      if (score >= 80) return { letter: 'B', color: 'bg-primary' };
      if (score >= 70) return { letter: 'C', color: 'bg-info text-dark' };
      if (score >= 60) return { letter: 'D', color: 'bg-warning text-dark' };
      return { letter: 'E', color: 'bg-danger' };
  };

  // Automated Calculations & Ranking
  const calculatedData = useMemo(() => {
    // 1. Calculate scores for everyone
    const processed = students.map(s => {
      const g = grades[s.id];
      if (!g) return null;

      const validF = g.formatif.filter(n => n > 0);
      const avgF = validF.length > 0 ? validF.reduce((a, b) => a + b, 0) / validF.length : 0;

      const validS = g.sumatif.filter(n => n > 0);
      const avgS = validS.length > 0 ? validS.reduce((a, b) => a + b, 0) / validS.length : 0;

      const sas = (g.sasNonTes + g.sasTes) / 2;

      const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);
      const isPassing = final >= KKM;
      const letter = getLetterGrade(final);

      return {
        ...s,
        g, // Keep raw grades for export
        avgF,
        avgS,
        sas,
        final,
        isPassing,
        letter
      };
    });

    // 2. Determine Ranks based on Score DESC
    // Filter out nulls first
    const validProcessed = processed.filter(p => p !== null) as NonNullable<typeof processed[0]>[];

    // Sort copy by final score DESC to determine rank
    const sortedByScore = [...validProcessed].sort((a, b) => b.final - a.final);

    // Create Map for Rank
    const rankMap: Record<string, number> = {};
    sortedByScore.forEach((item, index) => {
        rankMap[item.id] = index + 1;
    });

    // 3. Return original A-Z list with Rank attached
    return validProcessed.map(item => ({
        ...item,
        rank: rankMap[item.id]
    }));

  }, [students, grades]);

  // Stats
  const stats = useMemo(() => {
    if (!calculatedData.length) return null;
    const scores = calculatedData.map(d => d.final).filter(s => s > 0);
    if (!scores.length) return null;
    return {
      max: Math.max(...scores),
      min: Math.min(...scores),
      avg: scores.reduce((a,b) => a+b,0) / scores.length,
      tuntas: calculatedData.filter(d => d.isPassing).length,
      belum: calculatedData.filter(d => !d.isPassing).length,
    };
  }, [calculatedData]);

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    if (!selectedClass) return;
    const userProfile = getUserProfile();
    const className = classes.find(c => c.id === selectedClass)?.name || 'Kelas';
    const dateStr = new Date().toLocaleDateString('id-ID', {day: 'numeric', month: 'long', year: 'numeric'});
    const fileName = `Rekap_Nilai_${className.replace(/\s+/g, '_')}`;

    // 1. Generate Rows
    let tableRows = '';
    calculatedData.forEach((row, idx) => {
        let fCells = row.g.formatif.map(v => `<td style="text-align:center; border:1px solid #000;">${v || ''}</td>`).join('');
        let sCells = row.g.sumatif.map(v => `<td style="text-align:center; border:1px solid #000;">${v || ''}</td>`).join('');

        tableRows += `
            <tr>
                <td style="text-align:center; border:1px solid #000;">${idx + 1}</td>
                <td style="text-align:left; border:1px solid #000; padding-left:5px; white-space:nowrap;">${row.name}</td>
                ${fCells}
                <td style="text-align:center; font-weight:bold; background-color:#e2efda; border:1px solid #000;">${row.avgF.toFixed(0)}</td>
                ${sCells}
                <td style="text-align:center; font-weight:bold; background-color:#ddebf7; border:1px solid #000;">${row.avgS.toFixed(0)}</td>
                <td style="text-align:center; border:1px solid #000;">${row.g.sasNonTes}</td>
                <td style="text-align:center; border:1px solid #000;">${row.g.sasTes}</td>
                <td style="text-align:center; font-weight:bold; background-color:#fff2cc; border:1px solid #000;">${row.sas.toFixed(0)}</td>
                <td style="text-align:center; font-weight:bold; font-size:11pt; border:1px solid #000;">${row.final.toFixed(0)}</td>
                <td style="text-align:center; font-weight:bold; border:1px solid #000;">${row.letter.letter}</td>
                <td style="text-align:center; border:1px solid #000;">${row.rank}</td>
            </tr>
        `;
    });

    const contentHTML = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="utf-8">
            <title>${fileName}</title>
            <style>
                @page { size: A4 landscape; margin: 1cm; }
                body { font-family: 'Times New Roman', serif; font-size: 10pt; color: #000; }

                 /* KOP SURAT STYLE */
                .kop-table { width: 100%; border-bottom: 3px double #000; margin-bottom: 20px; }
                .kop-table td { border: none; padding: 0; vertical-align: middle; }
                .kop-logo { width: 90px; text-align: center; }
                .kop-text { text-align: center; }
                .kop-text h4 { margin: 0; font-size: 14pt; font-weight: normal; margin-bottom: 2px;}
                .kop-text h3 { margin: 0; font-size: 14pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text h2 { margin: 0; font-size: 16pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text p { margin: 0; font-size: 10pt; font-style: italic; }

                table.data-table { width: 100%; border-collapse: collapse; border-spacing: 0; margin-bottom: 20px; font-size: 9pt; }
                table.data-table th { border: 1px solid #000; padding: 4px; background-color: #d9d9d9; font-weight: bold; text-align: center; vertical-align: middle; }
                table.data-table td { border: 1px solid #000; padding: 2px; vertical-align: middle; }

                .title-doc { text-align: center; font-weight: bold; text-decoration: underline; font-size: 12pt; margin-top: 10px; margin-bottom: 5px; }
                .sub-title { text-align: center; margin-bottom: 20px; font-size: 11pt; }

                .signature-section { margin-top: 30px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <!-- KOP SURAT -->
            <table class="kop-table">
                <tr>
                    <td class="kop-logo">
                        <img src="${KEMENAG_LOGO_URL}" width="80" height="auto" alt="Logo">
                    </td>
                    <td class="kop-text">
                        <h4>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h4>
                        <h3>KANTOR KEMENTERIAN AGAMA KABUPATEN BULUKUMBA</h3>
                        <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                        <p>${KOP_ADDRESS}</p>
                    </td>
                </tr>
            </table>

            <div class="title-doc">REKAPITULASI NILAI BAHASA ARAB</div>
            <div class="sub-title">Kelas: ${className} | Tahun Pelajaran 2024/2025</div>

            <table class="data-table">
                <thead>
                    <tr>
                        <th rowspan="2" width="3%">NO</th>
                        <th rowspan="2" width="18%">NAMA SISWA</th>
                        <th colspan="8">FORMATIF (40%)</th>
                        <th rowspan="2" width="5%" style="background-color:#e2efda;">RATA F</th>
                        <th colspan="5">SUMATIF (30%)</th>
                        <th rowspan="2" width="5%" style="background-color:#ddebf7;">RATA S</th>
                        <th colspan="3">SUMATIF AKHIR (30%)</th>
                        <th rowspan="2" width="5%">NILAI RAPOR</th>
                        <th rowspan="2" width="4%">KET</th>
                        <th rowspan="2" width="4%">RANK</th>
                    </tr>
                    <tr>
                        <th width="3%">1</th><th width="3%">2</th><th width="3%">3</th><th width="3%">4</th>
                        <th width="3%">5</th><th width="3%">6</th><th width="3%">7</th><th width="3%">8</th>

                        <th width="3%">1</th><th width="3%">2</th><th width="3%">3</th><th width="3%">4</th><th width="3%">5</th>

                        <th width="5%">Non-Tes</th>
                        <th width="5%">Tes</th>
                        <th width="5%" style="background-color:#fff2cc;">NA SAS</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="70%"></td>
                        <td width="30%">
                            Bulukumba, ${dateStr}<br>
                            Guru Mata Pelajaran,<br>
                            <br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = '';
    let extension = '';

    if (type === 'excel') {
        mimeType = 'application/vnd.ms-excel';
        extension = 'xls';
    } else if (type === 'word') {
        mimeType = 'application/msword';
        extension = 'doc';
    }

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
         <h2 className="text-dark">Input & Rekap Nilai</h2>
         <div className="d-flex gap-2">
            <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
            >
                <option value="">-- Pilih Kelas --</option>
                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>

            {selectedClass && (
                 <div className="dropdown">
                    <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                        📥 Backup Data
                    </button>
                    <ul className="dropdown-menu">
                        <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel (Rapi)</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                    </ul>
                </div>
            )}
         </div>
      </div>

      {!selectedClass ? (
         <div className="alert alert-info text-center py-5">
            Silakan pilih kelas terlebih dahulu untuk mulai menginput nilai.
         </div>
      ) : (
         <>
         {/* Stats Summary */}
         {stats && (
            <div className="row g-3 mb-4 no-print">
               <div className="col-md-3">
                 <div className="card bg-success text-white">
                    <div className="card-body py-3">
                        <small className="opacity-75">Nilai Tertinggi</small>
                        <h4 className="fw-bold mb-0">{stats.max.toFixed(0)}</h4>
                    </div>
                 </div>
               </div>
               <div className="col-md-3">
                 <div className="card bg-danger text-white">
                    <div className="card-body py-3">
                        <small className="opacity-75">Nilai Terendah</small>
                        <h4 className="fw-bold mb-0">{stats.min.toFixed(0)}</h4>
                    </div>
                 </div>
               </div>
               <div className="col-md-3">
                 <div className="card bg-primary text-white">
                    <div className="card-body py-3">
                        <small className="opacity-75">Rata-rata Kelas</small>
                        <h4 className="fw-bold mb-0">{stats.avg.toFixed(1)}</h4>
                    </div>
                 </div>
               </div>
               <div className="col-md-3">
                 <div className="card bg-light border">
                    <div className="card-body py-3">
                        <small className="text-muted">Ketuntasan</small>
                        <div className="d-flex justify-content-between align-items-end">
                            <span className="text-success fw-bold">{stats.tuntas} Tuntas</span>
                            <span className="text-danger fw-bold">{stats.belum} Belum</span>
                        </div>
                    </div>
                 </div>
               </div>
            </div>
         )}

         {/* Grading Table */}
         <div className="card shadow-sm border-0">
           <div className="card-body p-0">
             <div className="table-responsive" style={{maxHeight: '75vh'}}>
                <table className="table table-bordered mb-0 align-middle text-center table-sm table-hover" style={{fontSize: '0.85rem'}}>
                    <thead className="table-success text-dark align-middle sticky-header">
                        <tr>
                            <th rowSpan={2} className="sticky-col sticky-header-col p-3" style={{minWidth: '200px'}}>NAMA SISWA</th>
                            <th colSpan={8} className="sticky-header">FORMATIF (40%)</th>
                            <th colSpan={5} className="sticky-header">SUMATIF (30%)</th>
                            <th colSpan={3} className="sticky-header">SAS (30%)</th>
                            <th rowSpan={2} className="bg-dark text-white sticky-header" style={{width: '60px'}}>RAPOR</th>
                            <th rowSpan={2} className="sticky-header">KET</th>
                            <th rowSpan={2} className="sticky-header">RANK</th>
                        </tr>
                        <tr>
                            {/* F1-F8 */}
                            {Array.from({length:8}, (_, i) => <th key={i} className="sticky-header bg-white">F{i+1}</th>)}
                            {/* S1-S5 */}
                            {Array.from({length:5}, (_, i) => <th key={i} className="sticky-header bg-white">S{i+1}</th>)}

                            <th className="sticky-header bg-white">Non</th>
                            <th className="sticky-header bg-white">Tes</th>
                            <th className="sticky-header bg-white">NA</th>
                        </tr>
                    </thead>
                    <tbody>
                        {calculatedData.map((row, idx) => (
                            <tr key={row.id}>
                                <td className="text-start ps-3 fw-bold sticky-col bg-white">
                                    {row.name}
                                </td>

                                {/* Formatif Inputs */}
                                {row.g.formatif.map((val, i) => (
                                    <td key={`f-${i}`} className="p-0">
                                        <input 
                                            type="text" 
                                            className="form-control border-0 text-center shadow-none p-1"
                                            value={val === 0 ? '' : val}
                                            onChange={(e) => handleGradeChange(row.id, 'formatif', i, e.target.value)}
                                            style={{fontSize: '0.85rem', minWidth: '35px'}}
                                        />
                                    </td>
                                ))}

                                {/* Sumatif Inputs */}
                                {row.g.sumatif.map((val, i) => (
                                    <td key={`s-${i}`} className="p-0">
                                        <input 
                                            type="text" 
                                            className="form-control border-0 text-center shadow-none p-1 bg-light"
                                            value={val === 0 ? '' : val}
                                            onChange={(e) => handleGradeChange(row.id, 'sumatif', i, e.target.value)}
                                            style={{fontSize: '0.85rem', minWidth: '35px'}}
                                        />
                                    </td>
                                ))}

                                {/* SAS Inputs */}
                                <td className="p-0">
                                     <input type="text" className="form-control border-0 text-center shadow-none p-1" value={row.g.sasNonTes || ''} onChange={(e) => handleSasChange(row.id, 'sasNonTes', e.target.value)} />
                                </td>
                                <td className="p-0">
                                     <input type="text" className="form-control border-0 text-center shadow-none p-1" value={row.g.sasTes || ''} onChange={(e) => handleSasChange(row.id, 'sasTes', e.target.value)} />
                                </td>
                                <td className="bg-light fw-bold text-muted">{row.sas.toFixed(0)}</td>

                                {/* Final Result */}
                                <td className="bg-dark text-white fw-bold h5 mb-0 py-2">
                                    {row.final.toFixed(0)}
                                </td>
                                <td>
                                    <span className={`badge ${row.letter.color}`}>{row.letter.letter}</span>
                                </td>
                                <td className="fw-bold text-primary">#{row.rank}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
             </div>
           </div>
         </div>
         </>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Classroom, Student, AttendanceData } from '../types';
import { getClasses, getStudentsByClass, getAttendanceByStudent, saveAttendance, getUserProfile } from '../services/storageService';
import { ATTENDANCE_OPTIONS, TOTAL_MEETINGS, SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';

export const AttendanceSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [attendance, setAttendance] = useState<Record<string, AttendanceData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const attMap: Record<string, AttendanceData> = {};
      clsStudents.forEach(s => {
        attMap[s.id] = getAttendanceByStudent(s.id);
      });
      setAttendance(attMap);
    }
  }, [selectedClass]);

  const handleStatusChange = (studentId: string, meetingIndex: number, status: string) => {
    const current = { ...attendance[studentId] };
    const newMeetings = [...current.meetings];
    newMeetings[meetingIndex] = status;
    current.meetings = newMeetings;

    setAttendance(prev => ({ ...prev, [studentId]: current }));
    saveAttendance(current);
  };

  const countStatus = (meetings: string[], status: string) => meetings.filter(m => m === status).length;

  const getStatusClass = (status: string) => {
    switch (status) {
      case 'H': return 'bg-att-H';
      case 'I': return 'bg-att-I';
      case 'S': return 'bg-att-S';
      case 'A': return 'bg-att-A';
      default: return 'bg-white';
    }
  };

