                        <th className="bg-warning text-dark sticky-header">I</th>
                        <th className="bg-info text-white sticky-header">S</th>
                        <th className="bg-danger text-white sticky-header">A</th>
                    </tr>
                    </thead>
                    <tbody>
                    {students.map(s => {
