    'selfira', 'rasmi', 'syifa', 'istanyah', 'khumairah', 'batrisya', 'arundaya', 'sabira'
  ];

  if (femaleKeywords.some(keyword => lower.includes(keyword))) {
    return Gender.P;
  }
  return Gender.L; // Default to L if unsure/male
};

