import React, { useState, useEffect, useMemo } from 'react';
import { Student, GradeData, Classroom } from '../types';
import { getClasses, getStudentsByClass, getGradeByStudent, saveGrade, getUserProfile } from '../services/storageService';
import { KKM, WEIGHTS, SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';

export const GradingSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [grades, setGrades] = useState<Record<string, GradeData>>({});

  // Save status indicator
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      // Data students already sorted A-Z from service
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const gradeMap: Record<string, GradeData> = {};
      clsStudents.forEach(s => {
        gradeMap[s.id] = getGradeByStudent(s.id);
      });
      setGrades(gradeMap);
    }
  }, [selectedClass]);

  // Helper untuk efek visual menyimpan
  const triggerAutoSave = (updatedGrade: GradeData) => {
      setSaveStatus('saving');
      saveGrade(updatedGrade);

      // Simulasi delay sedikit agar user melihat status "Saving..."
      setTimeout(() => {
          setSaveStatus('saved');
          setTimeout(() => setSaveStatus('idle'), 2000); // Hilang setelah 2 detik
      }, 600);
  };

  const handleGradeChange = (studentId: string, field: 'formatif' | 'sumatif', index: number, value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId] };
    if (field === 'formatif') {
      const newF = [...currentGrade.formatif];
      newF[index] = numVal;
      currentGrade.formatif = newF;
    } else {
      const newS = [...currentGrade.sumatif];
      newS[index] = numVal;
      currentGrade.sumatif = newS;
    }
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    triggerAutoSave(currentGrade);
  };

  const handleSasChange = (studentId: string, field: 'sasNonTes' | 'sasTes', value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId], [field]: numVal };
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    triggerAutoSave(currentGrade);
  };

  const getLetterGrade = (score: number) => {
      if (score >= 90) return { letter: 'A', color: 'bg-success' };
      if (score >= 80) return { letter: 'B', color: 'bg-primary' };
      if (score >= 70) return { letter: 'C', color: 'bg-info text-dark' };
      if (score >= 60) return { letter: 'D', color: 'bg-warning text-dark' };
      return { letter: 'E', color: 'bg-danger' };
  };

  // Automated Calculations & Ranking
  const calculatedData = useMemo(() => {
    // 1. Calculate scores for everyone
    const processed = students.map(s => {
      const g = grades[s.id];
      if (!g) return null;

      const validF = g.formatif.filter(n => n > 0);
      const avgF = validF.length > 0 ? validF.reduce((a, b) => a + b, 0) / validF.length : 0;

      const validS = g.sumatif.filter(n => n > 0);
      const avgS = validS.length > 0 ? validS.reduce((a, b) => a + b, 0) / validS.length : 0;

      const sas = (g.sasNonTes + g.sasTes) / 2;

      const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);
      const isPassing = final >= KKM;
      const letter = getLetterGrade(final);

      return {
        ...s,
        g, // Keep raw grades for export
        avgF,
        avgS,
        sas,
        final,
        isPassing,
        letter
      };
    });

    // 2. Determine Ranks based on Score DESC
    // Filter out nulls first
    const validProcessed = processed.filter(p => p !== null) as NonNullable<typeof processed[0]>[];

    // Sort copy by final score DESC to determine rank
    const sortedByScore = [...validProcessed].sort((a, b) => b.final - a.final);

    // Create Map for Rank
    const rankMap: Record<string, number> = {};
    sortedByScore.forEach((item, index) => {
        rankMap[item.id] = index + 1;
    });

    // 3. Return original A-Z list with Rank attached
    return validProcessed.map(item => ({
        ...item,
        rank: rankMap[item.id]
    }));

  }, [students, grades]);

  // Stats
  const stats = useMemo(() => {
    if (!calculatedData.length) return null;
    const scores = calculatedData.map(d => d.final).filter(s => s > 0);
    if (!scores.length) return null;
    return {
      max: Math.max(...scores),
      min: Math.min(...scores),
      avg: scores.reduce((a,b) => a+b,0) / scores.length,
      tuntas: calculatedData.filter(d => d.isPassing).length,
      belum: calculatedData.filter(d => !d.isPassing).length,
    };
  }, [calculatedData]);

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    if (!selectedClass) return;
    const userProfile = getUserProfile();
    const className = classes.find(c => c.id === selectedClass)?.name || 'Kelas';
    const dateStr = new Date().toLocaleDateString('id-ID', {day: 'numeric', month: 'long', year: 'numeric'});
    const fileName = `Rekap_Nilai_${className.replace(/\s+/g, '_')}`;

    // 1. Generate Rows
    let tableRows = '';
    calculatedData.forEach((row, idx) => {
        let fCells = row.g.formatif.map(v => `<td style="text-align:center; border:1px solid #000;">${v || ''}</td>`).join('');
        let sCells = row.g.sumatif.map(v => `<td style="text-align:center; border:1px solid #000;">${v || ''}</td>`).join('');

        tableRows += `
            <tr>
                <td style="text-align:center; border:1px solid #000;">${idx + 1}</td>
                <td style="text-align:left; border:1px solid #000; padding-left:5px; white-space:nowrap;">${row.name}</td>
                ${fCells}
                <td style="text-align:center; font-weight:bold; background-color:#e2efda; border:1px solid #000;">${row.avgF.toFixed(0)}</td>
                ${sCells}
                <td style="text-align:center; font-weight:bold; background-color:#ddebf7; border:1px solid #000;">${row.avgS.toFixed(0)}</td>
                <td style="text-align:center; border:1px solid #000;">${row.g.sasNonTes}</td>
                <td style="text-align:center; border:1px solid #000;">${row.g.sasTes}</td>
                <td style="text-align:center; font-weight:bold; background-color:#fff2cc; border:1px solid #000;">${row.sas.toFixed(0)}</td>
                <td style="text-align:center; font-weight:bold; font-size:11pt; border:1px solid #000;">${row.final.toFixed(0)}</td>
                <td style="text-align:center; font-weight:bold; border:1px solid #000;">${row.letter.letter}</td>
                <td style="text-align:center; border:1px solid #000;">${row.rank}</td>
            </tr>
        `;
    });

    const contentHTML = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="utf-8">
            <title>${fileName}</title>
            <style>
                @page { size: A4 landscape; margin: 1cm; }
                body { font-family: 'Times New Roman', serif; font-size: 10pt; color: #000; }

                 /* KOP SURAT STYLE */
                .kop-table { width: 100%; border-bottom: 3px double #000; margin-bottom: 20px; }
                .kop-table td { border: none; padding: 0; vertical-align: middle; }
                .kop-logo { width: 90px; text-align: center; }
                .kop-text { text-align: center; }
                .kop-text h4 { margin: 0; font-size: 14pt; font-weight: normal; margin-bottom: 2px;}
                .kop-text h3 { margin: 0; font-size: 14pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text h2 { margin: 0; font-size: 16pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text p { margin: 0; font-size: 10pt; font-style: italic; }

                table.data-table { width: 100%; border-collapse: collapse; border-spacing: 0; margin-bottom: 20px; font-size: 9pt; }
                table.data-table th { border: 1px solid #000; padding: 4px; background-color: #d9d9d9; font-weight: bold; text-align: center; vertical-align: middle; }
                table.data-table td { border: 1px solid #000; padding: 2px; vertical-align: middle; }

                .title-doc { text-align: center; font-weight: bold; text-decoration: underline; font-size: 12pt; margin-top: 10px; margin-bottom: 5px; }
                .sub-title { text-align: center; margin-bottom: 20px; font-size: 11pt; }

                .signature-section { margin-top: 30px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <!-- KOP SURAT -->
            <table class="kop-table">
                <tr>
                    <td class="kop-logo">
                        <img src="${KEMENAG_LOGO_URL}" width="80" height="auto" alt="Logo">
                    </td>
                    <td class="kop-text">
                        <h4>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h4>
                        <h3>KANTOR KEMENTERIAN AGAMA KABUPATEN BULUKUMBA</h3>
                        <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                        <p>${KOP_ADDRESS}</p>
                    </td>
                </tr>
            </table>

            <div class="title-doc">REKAPITULASI NILAI BAHASA ARAB</div>
            <div class="sub-title">Kelas: ${className} | Tahun Pelajaran 2024/2025</div>

            <table class="data-table">
                <thead>
                    <tr>
                        <th rowspan="2" width="3%">NO</th>
                        <th rowspan="2" width="18%">NAMA SISWA</th>
                        <th colspan="8">FORMATIF (40%)</th>
                        <th rowspan="2" width="5%" style="background-color:#e2efda;">RATA F</th>
                        <th colspan="5">SUMATIF (30%)</th>
                        <th rowspan="2" width="5%" style="background-color:#ddebf7;">RATA S</th>
                        <th colspan="3">SUMATIF AKHIR (30%)</th>
                        <th rowspan="2" width="5%">NILAI RAPOR</th>
                        <th rowspan="2" width="4%">KET</th>
                        <th rowspan="2" width="4%">RANK</th>
                    </tr>
                    <tr>
                        <th width="3%">1</th><th width="3%">2</th><th width="3%">3</th><th width="3%">4</th>
                        <th width="3%">5</th><th width="3%">6</th><th width="3%">7</th><th width="3%">8</th>

                        <th width="3%">1</th><th width="3%">2</th><th width="3%">3</th><th width="3%">4</th><th width="3%">5</th>

                        <th width="5%">Non-Tes</th>
                        <th width="5%">Tes</th>
                        <th width="5%" style="background-color:#fff2cc;">NA SAS</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="70%"></td>
                        <td width="30%">
                            Bulukumba, ${dateStr}<br>
                            Guru Mata Pelajaran,<br>
                            <br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = '';
    let extension = '';

    if (type === 'excel') {
        mimeType = 'application/vnd.ms-excel';
        extension = 'xls';
    } else if (type === 'word') {
        mimeType = 'application/msword';
        extension = 'doc';
    }

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
         <h2 className="text-dark">Input & Rekap Nilai</h2>
         <div className="d-flex gap-2">
            <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
