                table.data-table td { border: 1px solid #000; }

                .title-doc { text-align: center; font-weight: bold; text-decoration: underline; font-size: 12pt; margin-top: 10px; margin-bottom: 5px; }
                .sub-title { text-align: center; margin-bottom: 20px; }

                .signature-section { margin-top: 30px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <!-- KOP SURAT -->
            <table class="kop-table">
                <tr>
                    <td class="kop-logo">
                        <img src="${KEMENAG_LOGO_URL}" width="80" height="auto" alt="Logo">
                    </td>
                    <td class="kop-text">
                        <h4>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h4>
                        <h3>KANTOR KEMENTERIAN AGAMA KABUPATEN BULUKUMBA</h3>
                        <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                        <p>${KOP_ADDRESS}</p>
                    </td>
                </tr>
            </table>

            <div class="title-doc">REKAP ABSENSI SISWA</div>
            <div class="sub-title">Kelas: ${className} | Tahun Pelajaran 2024/2025</div>

            <table class="data-table">
                <thead>
                    <tr>
                        <th rowspan="2" width="3%">No</th>
                        <th rowspan="2" width="15%">Nama Siswa</th>
                        <th colspan="${TOTAL_MEETINGS}">Pertemuan Ke-</th>
                        <th colspan="4">Rekapitulasi</th>
                    </tr>
                    <tr>
                        ${meetingHeaders}
                        <th width="3%">H</th><th width="3%">I</th><th width="3%">S</th><th width="3%">A</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div style="margin-bottom: 20px; font-size: 10pt;">
                <strong>Keterangan:</strong> H = Hadir, I = Izin, S = Sakit, A = Alfa
            </div>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="70%"></td>
                        <td width="30%">
                            Bulukumba, ${dateStr}<br>
                            Guru Mata Pelajaran,<br>
                            <br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = type === 'excel' ? 'application/vnd.ms-excel' : 'application/msword';
    let extension = type === 'excel' ? 'xls' : 'doc';

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Absensi Siswa</h2>
        <div className="d-flex gap-2">
            <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
            >
                <option value="">-- Pilih Kelas --</option>
                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>

            {selectedClass && (
                <div className="d-flex align-items-center gap-2">
                    {/* Auto Save Status Indicator */}
                    {saveStatus === 'saving' && <span className="text-warning small fw-bold">⏳ Menyimpan...</span>}
                    {saveStatus === 'saved' && <span className="text-success small fw-bold">✅ Tersimpan</span>}

                    <div className="dropdown">
                        <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                            📥 Backup Data
                        </button>
                        <ul className="dropdown-menu">
                            <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel (Rapi)</button></li>
                            <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                            <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                        </ul>
                    </div>
                </div>
            )}
        </div>
      </div>

      {selectedClass && (
        <div className="card shadow-sm border-0">
          <div className="card-body p-0">
             {/* Legend */}
             <div className="p-3 border-bottom bg-light d-flex gap-3 flex-wrap">
                <span className="fw-bold">Keterangan:</span>
                <span className="badge bg-att-H text-dark border">H = Hadir</span>
                <span className="badge bg-att-I text-dark border">I = Izin</span>
                <span className="badge bg-att-S text-dark border">S = Sakit</span>
                <span className="badge bg-att-A text-dark border">A = Alfa</span>
             </div>

            <div className="table-responsive" style={{maxHeight: '75vh'}}>
                <table id="attendance-table" className="table table-bordered mb-0 align-middle text-center" style={{fontSize: '0.9rem'}}>
                    <thead className="table-light sticky-header">
                    <tr>
                        <th rowSpan={2} className="align-middle sticky-col sticky-header-col p-3" style={{minWidth: '250px', left: 0}}>
                            NAMA SISWA (A-Z)
                        </th>
                        <th colSpan={TOTAL_MEETINGS} className="text-center py-2 bg-light sticky-header">Pertemuan Ke-</th>
                        <th colSpan={4} className="text-center bg-light sticky-header">Total</th>
                    </tr>
                    <tr>
                        {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                        <th key={i} className="small text-muted sticky-header bg-white" style={{minWidth: '60px'}}>{i + 1}</th>
                        ))}
                        <th className="bg-success text-white sticky-header">H</th>
                        <th className="bg-warning text-dark sticky-header">I</th>
                        <th className="bg-info text-white sticky-header">S</th>
                        <th className="bg-danger text-white sticky-header">A</th>
                    </tr>
                    </thead>
                    <tbody>
                    {students.map(s => {
                        const att = attendance[s.id];
                        if (!att) return null;
                        return (
                        <tr key={s.id}>
                            <td className="sticky-col text-start fw-bold px-3 py-2 bg-white">{s.name}</td>
                            {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                            <td key={i} className="p-0">
                                <select 
                                    className={`form-select border-0 shadow-none att-select ${getStatusClass(att.meetings[i])}`}
                                    value={att.meetings[i] || ''}
                                    onChange={(e) => handleStatusChange(s.id, i, e.target.value)}
                                >
                                    <option value="">-</option>
                                    {ATTENDANCE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                                </select>
                            </td>
                            ))}
                            <td className="fw-bold">{countStatus(att.meetings, 'H')}</td>
                            <td>{countStatus(att.meetings, 'I')}</td>
                            <td>{countStatus(att.meetings, 'S')}</td>
                            <td className="fw-bold text-danger">{countStatus(att.meetings, 'A')}</td>
                        </tr>
                        );
                    })}
                    </tbody>
                </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { UserProfile } from '../types';
import { saveUserProfile } from '../services/storageService';

interface ProfileManagerProps {
  userProfile: UserProfile;
  onProfileUpdate: (updated: UserProfile) => void;
}

export const ProfileManager: React.FC<ProfileManagerProps> = ({ userProfile, onProfileUpdate }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<UserProfile>(userProfile);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const restoreInputRef = useRef<HTMLInputElement>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  // Fungsi untuk Memproses Foto (Resize & Compress) agar muat di LocalStorage
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        // Validasi tipe file
        if (!file.type.startsWith('image/')) {
            alert('Mohon upload file gambar yang valid.');
            return;
        }

        const resizeAndCompressImage = (imageFile: File): Promise<string> => {
            return new Promise((resolve) => {
                const reader = new FileReader();
                reader.onload = (readerEvent) => {
                    const img = new Image();
                    img.onload = () => {
                        const canvas = document.createElement('canvas');
                        const MAX_SIZE = 400; // Maksimal ukuran sisi 400px (Cukup untuk avatar)
                        let width = img.width;
                        let height = img.height;

                        // Hitung aspek rasio untuk resize
                        if (width > height) {
                            if (width > MAX_SIZE) {
                                height *= MAX_SIZE / width;
                                width = MAX_SIZE;
                            }
                        } else {
                            if (height > MAX_SIZE) {
                                width *= MAX_SIZE / height;
                                height = MAX_SIZE;
                            }
                        }

                        canvas.width = width;
                        canvas.height = height;
                        const ctx = canvas.getContext('2d');
                        if (ctx) {
                            ctx.drawImage(img, 0, 0, width, height);
                            // Konversi ke JPEG dengan kualitas 70% untuk menghemat penyimpanan
                            const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
                            resolve(dataUrl);
                        } else {
                            // Fallback jika canvas gagal (jarang terjadi)
                            resolve(readerEvent.target?.result as string);
                        }
                    };
                    img.src = readerEvent.target?.result as string;
                };
                reader.readAsDataURL(imageFile);
            });
        };

        const compressedPhoto = await resizeAndCompressImage(file);
        setFormData(prev => ({ ...prev, photo: compressedPhoto }));
      } catch (error) {
          console.error("Gagal memproses gambar:", error);
          alert("Terjadi kesalahan saat memproses gambar.");
      }
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    saveUserProfile(formData);
    onProfileUpdate(formData);
    setIsEditing(false);
  };

  // Trigger klik input file secara manual
  const triggerFileInput = () => {
      if (fileInputRef.current) {
          fileInputRef.current.value = ''; // Reset value agar bisa upload file yang sama jika perlu
          fileInputRef.current.click();
      }
  };

  // --- BACKUP & RESTORE LOGIC ---
  const handleDownloadBackup = () => {
    const keys = ['ar_classes', 'ar_students', 'ar_grades', 'ar_attendance', 'ar_journal', 'ar_user_profile'];
    const backup: Record<string, any> = {};

    keys.forEach(k => {
        const raw = localStorage.getItem(k);
        if (raw) backup[k] = JSON.parse(raw);
    });

    const json = JSON.stringify(backup, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `BACKUP_NILAI_MTSN2_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const handleRestoreBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
        try {
            const json = event.target?.result as string;
            const data = JSON.parse(json);

            // Validasi sederhana
            if (!data.ar_classes && !data.ar_students) {
                alert('File tidak valid! Pastikan file adalah hasil backup dari aplikasi ini.');
                return;
            }

            if (confirm('PERINGATAN: Fitur ini akan MENIMPA (MENGHAPUS) semua data yang ada saat ini dengan data dari file backup.\n\nApakah Anda yakin ingin melanjutkan?')) {
                Object.keys(data).forEach(key => {
                    localStorage.setItem(key, JSON.stringify(data[key]));
                });
                alert('Data berhasil dipulihkan! Aplikasi akan dimuat ulang.');
                window.location.reload();
            }
        } catch (err) {
            console.error(err);
            alert('Gagal membaca file backup. Pastikan format file benar (JSON).');
        }
    };
    reader.readAsText(file);
    // Reset input agar bisa pilih file yang sama jika perlu
    if (restoreInputRef.current) restoreInputRef.current.value = ''; 
  };

  return (
    <div className="container-fluid">
      <h2 className="mb-4 text-dark font-arabic">Profil Pengguna</h2>

      <div className="row g-4 justify-content-center">
        <div className="col-lg-8">
          <div className="card shadow-lg border-0 overflow-hidden">
            <div className="card-header bg-success text-white p-4 text-center position-relative" style={{backgroundImage: 'linear-gradient(45deg, #0f5132, #198754)'}}>
               {/* Decorative Circle Background */}
               <div style={{
                   position: 'absolute', top: '-50%', left: '50%', transform: 'translateX(-50%)', 
                   width: '400px', height: '400px', background: 'rgba(255,255,255,0.1)', 
                   borderRadius: '50%', zIndex: 0
               }}></div>

               <div className="position-relative" style={{zIndex: 1}}>
                   <div className="mb-3 d-inline-block p-1 bg-white rounded-circle shadow position-relative">
                        {formData.photo ? (
                            <img 
                                src={formData.photo} 
                                alt="Profile" 
                                className="rounded-circle object-fit-cover" 
                                style={{width: '120px', height: '120px'}}
                            />
                        ) : (
                            <div className="rounded-circle bg-light d-flex align-items-center justify-content-center text-secondary" style={{width: '120px', height: '120px', fontSize: '3rem'}}>
                                👤
                            </div>
                        )}

                        {/* Tombol Edit Cepat di Foto saat Mode Edit */}
                        {isEditing && (
                            <button 
                                type="button"
                                onClick={triggerFileInput}
                                className="btn btn-sm btn-warning position-absolute bottom-0 end-0 rounded-circle border border-white shadow-sm"
                                style={{width: '35px', height: '35px', padding: 0}}
                                title="Ganti Foto"
                            >
                                📷
                            </button>
                        )}
                   </div>
                   <h3 className="font-arabic mb-0">{isEditing ? formData.name : userProfile.name}</h3>
                   <p className="opacity-75 mb-0">{isEditing ? formData.role : userProfile.role}</p>
               </div>
            </div>

            <div className="card-body p-4">
              {!isEditing ? (
                <>
                <div className="row g-4">
                  <div className="col-md-6">
                    <label className="text-muted small text-uppercase fw-bold mb-1">Nama Lengkap</label>
                    <div className="fs-5 fw-bold text-dark border-bottom pb-2">{userProfile.name}</div>
                  </div>
                  <div className="col-md-6">
                     <label className="text-muted small text-uppercase fw-bold mb-1">NIP</label>
                     <div className="fs-5 fw-bold text-dark border-bottom pb-2">{userProfile.nip || '-'}</div>
                  </div>
                  <div className="col-md-6">
                     <label className="text-muted small text-uppercase fw-bold mb-1">Jabatan</label>
                     <div className="fs-5 fw-bold text-dark border-bottom pb-2">{userProfile.role}</div>
                  </div>
                  <div className="col-md-6">
                     <label className="text-muted small text-uppercase fw-bold mb-1">Status Akun</label>
                     <div className="fs-5 fw-bold text-success border-bottom pb-2">✅ Aktif</div>
                  </div>

                  <div className="col-12 text-center mt-4">
                    <button className="btn btn-primary px-5" onClick={() => setIsEditing(true)}>
                        ✏️ Edit Profil
                    </button>
                  </div>
                </div>

                {/* AREA BACKUP DATA */}
                <div className="mt-5 pt-4 border-top">
                    <h5 className="text-dark font-arabic mb-3">💾 Keamanan Data</h5>
                    <div className="alert alert-info border-0 shadow-sm">
                        <small>
                            Data tersimpan otomatis di browser ini. Agar data aman saat pindah perangkat atau jika laptop di-reset, silakan <strong>Download Backup</strong> secara berkala.
                        </small>
                    </div>
                    <div className="d-flex gap-3 justify-content-center flex-wrap">
                        <button onClick={handleDownloadBackup} className="btn btn-outline-success">
                            ⬇️ Download Backup Data (.json)
                        </button>

                        <div className="position-relative">
                             <button className="btn btn-outline-warning text-dark" onClick={() => restoreInputRef.current?.click()}>
                                ⬆️ Restore Data dari File
                            </button>
                            <input 
                                type="file" 
                                ref={restoreInputRef} 
                                className="d-none" 
                                accept=".json" 
                                onChange={handleRestoreBackup}
                            />
                        </div>
                    </div>
                </div>
                </>
              ) : (
                <form onSubmit={handleSubmit}>
                   <div className="row g-3">
                       <div className="col-12 text-center mb-3">
                           <button 
                                type="button" 
                                className="btn btn-outline-secondary btn-sm"
                                onClick={triggerFileInput}
                            >
                                📷 Ganti Foto
                           </button>
                           <small className="d-block text-muted mt-2">Format: JPG/PNG. Ukuran akan otomatis disesuaikan.</small>
                           <input 
                                type="file" 
                                ref={fileInputRef} 
                                onChange={handleFileChange} 
                                className="d-none" 
                                accept="image/*"
                           />
                       </div>

                       <div className="col-md-12">
                           <label className="form-label">Nama Lengkap & Gelar</label>
                           <input 
                                type="text" 
                                name="name"
                                className="form-control" 
                                value={formData.name} 
                                onChange={handleInputChange} 
                                required 
                           />
                       </div>

                       <div className="col-md-6">
                           <label className="form-label">NIP</label>
                           <input 
                                type="text" 
                                name="nip"
                                className="form-control" 
                                value={formData.nip} 
                                onChange={handleInputChange} 
                           />
                       </div>

                       <div className="col-md-6">
                           <label className="form-label">Jabatan</label>
                           <input 
                                type="text" 
                                name="role"
                                className="form-control" 
                                value={formData.role} 
                                onChange={handleInputChange} 
                           />
                       </div>
                   </div>

                   <div className="d-flex gap-2 justify-content-end mt-4">
                       <button type="button" className="btn btn-light border" onClick={() => { setIsEditing(false); setFormData(userProfile); }}>
                           Batal
                       </button>
                       <button type="submit" className="btn btn-success px-4">
                           💾 Simpan Perubahan
                       </button>
                   </div>
                </form>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};
